class Solution:
    def getSmallestString(self, s: str, k: int) -> str:
        res = list(s)
        for i, c in enumerate(s):
            d = ord(c) - ord('a')
            dist = min(d, 26 - d)
            if dist <= k:
                k -= dist
                res[i] = 'a'
            else:
                # spend all k to get as lex-small as possible
                # going down by k gives chr(ord(c)-k), valid if k <= d
                # going up by k gives chr(ord(c)+k), valid if k <= 25-d
                # going down always lex-smaller than going up; prefer down
                if k <= d:
                    res[i] = chr(ord(c) - k)
                else:
                    res[i] = chr(ord(c) + k)
                k = 0
                break
        return ''.join(res)

