var getSmallestString = function(s, k) {
    const res = s.split('');
    for (let i = 0; i < s.length; i++) {
        const d = s.charCodeAt(i) - 97;
        const dist = Math.min(d, 26 - d);
        if (dist <= k) {
            k -= dist;
            res[i] = 'a';
        } else {
            if (k <= d) {
                res[i] = String.fromCharCode(s.charCodeAt(i) - k);
            } else {
                res[i] = String.fromCharCode(s.charCodeAt(i) + k);
            }
            break;
        }
    }
    return res.join('');
};
